#!/usr/bin/env python3
import os
import re
import sys
import subprocess
from datetime import datetime

CERT = "/app/ssl/server.crt"


def load_with_cryptography():
    from cryptography import x509
    from cryptography.hazmat.backends import default_backend

    with open(CERT, "rb") as f:
        cert = x509.load_pem_x509_certificate(f.read(), default_backend())
    cn = cert.subject.get_attributes_for_oid(x509.oid.NameOID.COMMON_NAME)[0].value
    try:
        expire = cert.not_valid_after_utc
    except AttributeError:
        expire = cert.not_valid_after
    return cn, expire.strftime("%Y-%m-%d")


def load_with_openssl():
    subj = subprocess.check_output(
        ["openssl", "x509", "-in", CERT, "-noout", "-subject"], text=True
    )
    m = re.search(r"CN\s*=\s*([^,/\n]+)", subj)
    cn = m.group(1).strip() if m else ""
    end = subprocess.check_output(
        ["openssl", "x509", "-in", CERT, "-noout", "-enddate"], text=True
    ).split("=", 1)[1].strip()
    dt = datetime.strptime(end, "%b %d %H:%M:%S %Y %Z")
    return cn, dt.strftime("%Y-%m-%d")


def main():
    if not os.path.exists(CERT):
        print("Certificate verification failed: certificate not found")
        sys.exit(1)
    try:
        try:
            cn, expire = load_with_cryptography()
        except ImportError:
            cn, expire = load_with_openssl()
    except Exception as e:
        print("Certificate verification failed:", e)
        sys.exit(1)

    print("Certificate loaded successfully")
    print("Common Name:", cn)
    print("Expiration date:", expire)
    print("Certificate verification successful")


if __name__ == "__main__":
    main()

